<div class="header">
  <h1>Comments Insights</h1>
  <p>YouTube Analytics Dashboard</p>
</div>

<div class="grid">

  <div class="card col-4">
    <div class="card-title">Sentiment Overview</div>
    <div class="chart-wrap">
      <canvas id="sentimentChart"></canvas>
    </div>
  </div>

  <div class="card col-4">
    <div class="card-title">Sentiment Breakdown</div>
    <div class="sentiment-pills" id="sentimentBars"></div>
  </div>

  <div class="card col-4">
    <div class="card-title">Top Keywords</div>
    <div class="tags" id="keywordTags"></div>
  </div>

  <div class="card col-6">
    <div class="card-title">Top Complaints</div>
    <div class="chart-wrap">
      <canvas id="complaintsChart"></canvas>
    </div>
  </div>

  <div class="card col-6">
    <div class="card-title">Top Requests</div>
    <div class="chart-wrap">
      <canvas id="requestsChart"></canvas>
    </div>
  </div>

  <div class="card col-12">
    <div class="card-title">Most Engaged Comments</div>
    <div class="comment-list" id="commentList"></div>
  </div>

</div>

<script>
  const data = {{ JSON.stringify($json) }};

  const C = {
    positive: '#1a9e4a',
    negative: '#e8284a',
    neutral:  '#d4a000',
    red:      '#e8284a',
    blue:     '#0062cc',
    border:   '#e2e4ed',
    muted:    '#6b7280',
    text:     '#1a1a2e',
  };

  Chart.defaults.color = '#6b7280';
  Chart.defaults.font.family = "'DM Sans', sans-serif";

  // Sentiment Donut
  const sentColors = data.sentiment.map(s =>
    s.sentiment_label === 'positive' ? C.positive :
    s.sentiment_label === 'negative' ? C.negative : C.neutral
  );

  new Chart(document.getElementById('sentimentChart'), {
    type: 'doughnut',
    data: {
      labels: data.sentiment.map(s => s.sentiment_label),
      datasets: [{
        data: data.sentiment.map(s => s.count),
        backgroundColor: sentColors,
        borderColor: '#ffffff',
        borderWidth: 3,
        hoverOffset: 6,
      }]
    },
    options: {
      cutout: '72%',
      plugins: {
        legend: {
          position: 'bottom',
          labels: { padding: 16, boxWidth: 10, borderRadius: 3 }
        }
      }
    }
  });

  // Sentiment Bars
  const total = data.sentiment.reduce((a, s) => a + s.count, 0);
  const barsEl = document.getElementById('sentimentBars');
  data.sentiment.forEach(s => {
    const pct = Math.round((s.count / total) * 100);
    const color = s.sentiment_label === 'positive' ? C.positive :
                  s.sentiment_label === 'negative' ? C.negative : C.neutral;
    barsEl.innerHTML += `
      <div class="pill-row">
        <span class="pill-label">${s.sentiment_label}</span>
        <div class="pill-bar-wrap">
          <div class="pill-bar" style="width:${pct}%;background:${color}"></div>
        </div>
        <span class="pill-count">${s.count}</span>
      </div>`;
  });

  // Keywords
  const tagsEl = document.getElementById('keywordTags');
  data.keywords.forEach(k => {
    tagsEl.innerHTML += `<div class="tag">${k.keyword}<span>${k.count}</span></div>`;
  });

  // Complaints Chart
  new Chart(document.getElementById('complaintsChart'), {
    type: 'bar',
    data: {
      labels: data.topComplaints.map(c => c.issue),
      datasets: [{
        label: 'Count',
        data: data.topComplaints.map(c => c.count),
        backgroundColor: 'rgba(232,40,74,0.12)',
        borderColor: C.red,
        borderWidth: 2,
        borderRadius: 6,
      }]
    },
    options: {
      indexAxis: 'y',
      plugins: { legend: { display: false } },
      scales: {
        x: { grid: { color: '#e2e4ed' }, ticks: { stepSize: 1 } },
        y: { grid: { display: false } }
      }
    }
  });

  // Requests Chart
  new Chart(document.getElementById('requestsChart'), {
    type: 'bar',
    data: {
      labels: data.topRequests.map(r => r.request),
      datasets: [{
        label: 'Count',
        data: data.topRequests.map(r => r.count),
        backgroundColor: 'rgba(0,98,204,0.12)',
        borderColor: C.blue,
        borderWidth: 2,
        borderRadius: 6,
      }]
    },
    options: {
      indexAxis: 'y',
      plugins: { legend: { display: false } },
      scales: {
        x: { grid: { color: '#e2e4ed' }, ticks: { stepSize: 1 } },
        y: { grid: { display: false } }
      }
    }
  });

  // Comments
  const listEl = document.getElementById('commentList');
  data.mostEngaged.forEach(c => {
    listEl.innerHTML += `<div class="comment-item">${c.text}</div>`;
  });
</script>
</body>
</html>

