    font-weight: 800;
    background: linear-gradient(135deg, #e8284a, #ff6b35);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    letter-spacing: -1px;
  }

  .header p {
    color: var(--muted);
    margin-top: 8px;
    font-size: 14px;
    letter-spacing: 2px;
    text-transform: uppercase;
  }

  .grid {
    max-width: 1100px;
    margin: 0 auto;
    display: grid;
    grid-template-columns: repeat(12, 1fr);
    gap: 16px;
  }

  .card {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 16px;
    padding: 24px;
    animation: fadeUp 0.5s ease both;
    box-shadow: 0 2px 12px rgba(0,0,0,0.06);
  }

  .card:nth-child(1) { animation-delay: 0.1s; }
  .card:nth-child(2) { animation-delay: 0.2s; }
  .card:nth-child(3) { animation-delay: 0.3s; }
  .card:nth-child(4) { animation-delay: 0.4s; }
  .card:nth-child(5) { animation-delay: 0.5s; }
  .card:nth-child(6) { animation-delay: 0.6s; }

  .col-4  { grid-column: span 4; }
  .col-5  { grid-column: span 5; }
  .col-6  { grid-column: span 6; }
  .col-7  { grid-column: span 7; }
  .col-12 { grid-column: span 12; }

  @media (max-width: 768px) {
    .col-4, .col-5, .col-6, .col-7 { grid-column: span 12; }
  }

  .card-title {
    font-family: 'Syne', sans-serif;
    font-size: 11px;
    font-weight: 600;
    letter-spacing: 2px;
    text-transform: uppercase;
    color: var(--muted);
    margin-bottom: 20px;
    display: flex;
    align-items: center;
    gap: 8px;
  }

  .card-title::before {
    content: '';
    display: block;
    width: 6px;
    height: 6px;
    border-radius: 50%;
    background: var(--red);
  }

  .chart-wrap {
    position: relative;
    height: 220px;
  }

  .sentiment-pills {
    display: flex;
    flex-direction: column;
    gap: 12px;
    margin-top: 8px;
  }

  .pill-row {
    display: flex;
    align-items: center;
    gap: 12px;
  }

  .pill-label {
    font-size: 12px;
    font-weight: 500;
    width: 70px;
    text-transform: capitalize;
    color: var(--text);
  }

  .pill-bar-wrap {
    flex: 1;
    height: 8px;
    background: var(--surface2);
    border-radius: 99px;
    overflow: hidden;
  }

  .pill-bar {
    height: 100%;
    border-radius: 99px;
    transition: width 1s ease;
  }

  .pill-count {
    font-size: 13px;
    font-weight: 600;
    width: 30px;
    text-align: right;
    color: var(--muted);
  }

  .tags {
    display: flex;
    flex-wrap: wrap;
    gap: 8px;
    margin-top: 8px;
  }

  .tag {
    background: var(--surface2);
    border: 1px solid var(--border);
    border-radius: 99px;
    padding: 5px 14px;
    font-size: 12px;
    font-weight: 500;
    color: var(--text);
    display: flex;
    align-items: center;
    gap: 6px;
  }

  .tag span {
    background: var(--red);
    color: white;
    font-size: 10px;
    font-weight: 700;
    border-radius: 99px;
    padding: 1px 6px;
  }

  .comment-list {
    display: flex;
    flex-direction: column;
    gap: 12px;
    max-height: 320px;
    overflow-y: auto;
    padding-right: 4px;
  }

  .comment-list::-webkit-scrollbar { width: 4px; }
  .comment-list::-webkit-scrollbar-track { background: var(--surface2); border-radius: 99px; }
  .comment-list::-webkit-scrollbar-thumb { background: var(--border); border-radius: 99px; }

  .comment-item {
    background: var(--surface2);
    border-left: 3px solid var(--red);
    border-radius: 0 10px 10px 0;
    padding: 12px 16px;
    font-size: 13px;
    line-height: 1.6;
    color: var(--text);
  }

  @keyframes fadeDown {
    from { opacity: 0; transform: translateY(-20px); }
    to   { opacity: 1; transform: translateY(0); }
  }

  @keyframes fadeUp {
    from { opacity: 0; transform: translateY(24px); }
    to   { opacity: 1; transform: translateY(0); }
  }
</style>
</head>
<body>

<div class="header">
  <h1>Comments Insights</h1>
  <p>YouTube Analytics Dashboard</p>
</div>

<div class="grid">

  <div class="card col-4">
    <div class="card-title">Sentiment Overview</div>
    <div class="chart-wrap">
      <canvas id="sentimentChart"></canvas>
    </div>
  </div>

  <div class="card col-4">
    <div class="card-title">Sentiment Breakdown</div>
    <div class="sentiment-pills" id="sentimentBars"></div>
  </div>

  <div class="card col-4">
    <div class="card-title">Top Keywords</div>
    <div class="tags" id="keywordTags"></div>
  </div>

  <div class="card col-6">
    <div class="card-title">Top Complaints</div>
    <div class="chart-wrap">
      <canvas id="complaintsChart"></canvas>
    </div>
  </div>

  <div class="card col-6">
    <div class="card-title">Top Requests</div>
    <div class="chart-wrap">
      <canvas id="requestsChart"></canvas>
    </div>
  </div>

  <div class="card col-12">
    <div class="card-title">Most Engaged Comments</div>
    <div class="comment-list" id="commentList"></div>
  </div>

</div>

<script>
  const data = {{ JSON.stringify($json) }};

  const C = {
    positive: '#1a9e4a',
    negative: '#e8284a',
    neutral:  '#d4a000',
    red:      '#e8284a',
    blue:     '#0062cc',
    border:   '#e2e4ed',
    muted:    '#6b7280',
    text:     '#1a1a2e',
  };

  Chart.defaults.color = '#6b7280';
  Chart.defaults.font.family = "'DM Sans', sans-serif";

  // Sentiment Donut
  const sentColors = data.sentiment.map(s =>
    s.sentiment_label === 'positive' ? C.positive :
    s.sentiment_label === 'negative' ? C.negative : C.neutral
  );

  new Chart(document.getElementById('sentimentChart'), {
    type: 'doughnut',
    data: {
      labels: data.sentiment.map(s => s.sentiment_label),
      datasets: [{
        data: data.sentiment.map(s => s.count),
        backgroundColor: sentColors,
        borderColor: '#ffffff',
        borderWidth: 3,
        hoverOffset: 6,
      }]
    },
    options: {
      cutout: '72%',
      plugins: {
        legend: {
          position: 'bottom',
          labels: { padding: 16, boxWidth: 10, borderRadius: 3 }
        }
      }
    }
  });

  // Sentiment Bars
  const total = data.sentiment.reduce((a, s) => a + s.count, 0);
  const barsEl = document.getElementById('sentimentBars');
  data.sentiment.forEach(s => {
    const pct = Math.round((s.count / total) * 100);
    const color = s.sentiment_label === 'positive' ? C.positive :
                  s.sentiment_label === 'negative' ? C.negative : C.neutral;
    barsEl.innerHTML += `
      <div class="pill-row">
        <span class="pill-label">${s.sentiment_label}</span>
        <div class="pill-bar-wrap">
          <div class="pill-bar" style="width:${pct}%;background:${color}"></div>
        </div>
        <span class="pill-count">${s.count}</span>
      </div>`;
  });

  // Keywords
  const tagsEl = document.getElementById('keywordTags');
  data.keywords.forEach(k => {
    tagsEl.innerHTML += `<div class="tag">${k.keyword}<span>${k.count}</span></div>`;
  });

  // Complaints Chart
  new Chart(document.getElementById('complaintsChart'), {
    type: 'bar',
    data: {
      labels: data.topComplaints.map(c => c.issue),
      datasets: [{
        label: 'Count',
        data: data.topComplaints.map(c => c.count),
        backgroundColor: 'rgba(232,40,74,0.12)',
        borderColor: C.red,
        borderWidth: 2,
        borderRadius: 6,
      }]
    },
    options: {
      indexAxis: 'y',
      plugins: { legend: { display: false } },
      scales: {
        x: { grid: { color: '#e2e4ed' }, ticks: { stepSize: 1 } },
        y: { grid: { display: false } }
      }
    }
  });

  // Requests Chart
  new Chart(document.getElementById('requestsChart'), {
    type: 'bar',
    data: {
      labels: data.topRequests.map(r => r.request),
      datasets: [{
        label: 'Count',
        data: data.topRequests.map(r => r.count),
        backgroundColor: 'rgba(0,98,204,0.12)',
        borderColor: C.blue,
        borderWidth: 2,
        borderRadius: 6,
      }]
    },
    options: {
      indexAxis: 'y',
      plugins: { legend: { display: false } },
      scales: {
        x: { grid: { color: '#e2e4ed' }, ticks: { stepSize: 1 } },
        y: { grid: { display: false } }
      }
    }
  });

  // Comments
  const listEl = document.getElementById('commentList');
  data.mostEngaged.forEach(c => {
    listEl.innerHTML += `<div class="comment-item">${c.text}</div>`;
  });
</script>
</body>
</html>
